class Solution {
    public List<Integer> maxScoreIndices(int[] nums) {
        int n = nums.length;
        int[] prefixOnes = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixOnes[i + 1] = prefixOnes[i] + nums[i];
        }
        int totalOnes = prefixOnes[n];
        int maxScore = 0;
        List<Integer> result = new ArrayList<>();
        for (int i = 0; i <= n; i++) {
            int zerosLeft = i;
            int onesRight = totalOnes - prefixOnes[i];
            int score = zerosLeft + onesRight;
            if (score > maxScore) {
                maxScore = score;
                result.clear();
                result.add(i);
            } else if (score == maxScore) {
                result.add(i);
            }
        }
        return result;
    }
}
